#include "bearing_fault_class_data.h"

/**
 * @brief Get the current Bearing Fault class data pointer
 *
 * @return Pointer to the currently selected class data array
 */
const int32_t *get_current_bearing_fault_class_data(void)
{
    /* Return the appropriate class data array based on the current class index */
    #if (CLASS_1) /* Normal Bearing Fault - Class 1 */
        return BEARING_FAULT_CLASS_NORMAL;
    #elif (CLASS_2) /* Contaminated - Class 2 */
        return BEARING_FAULT_CLASS_CONTAMINATED;
    #elif (CLASS_3) /* Erosion - Class 3 */
        return BEARING_FAULT_CLASS_EROSION;
    #elif (CLASS_4) /* Flaking - Class 4 */
        return BEARING_FAULT_CLASS_FLAKING;
    #elif (CLASS_5) /* No Lubrication - Class 5 */
        return BEARING_FAULT_CLASS_NOLUBRICATION;
    #elif (CLASS_6) /* Localized fault - Class 6 */
        return BEARING_FAULT_CLASS_LOCALIZEDFAULT;
    #endif
    return (const int32_t *)NULL; /* Default to normal as fallback */
}

